public int compareTo(Fraction object) {
    if (this.numerator == 0 && object.numerator == 0) return 0;
    if (object.denominator == 0 || this.denominator == 0) return Integer.MAX_VALUE;
    if (this.numerator * object.denominator < object.numerator * this.denominator) return -1;
    if (this.numerator * object.denominator > object.numerator * this.denominator) return 1;
    return 0;
}
